const crypto = require('crypto');
const item = $input.first();
const rawBody = item.json.body || '';
const headers = item.json.headers || {};

// -- Slack request signing verification --
const signingSecret = $env.SLACK_SIGNING_SECRET || '';
if (signingSecret) {
  const ts = headers['x-slack-request-timestamp'] || '';
  const sig = headers['x-slack-signature'] || '';
  const basestring = `v0:${ts}:${rawBody}`;
  const expected = 'v0=' + crypto.createHmac('sha256', signingSecret)
    .update(basestring).digest('hex');
  if (sig && !crypto.timingSafeEqual(Buffer.from(expected), Buffer.from(sig))) {
    throw new Error('Slack signature verification failed');
  }
}

// -- Parse Slack interactive payload (URL-encoded form) --
const params = new URLSearchParams(rawBody);
const payload = JSON.parse(params.get('payload') || '{}');

const action = (payload.actions || [])[0] || {};
let actionValue = {};
try { actionValue = JSON.parse(action.value || '{}'); } catch (_) {}
const user = payload.user || {};

return [{
  json: {
    taskId: actionValue.taskId || '',
    assignedUserId: actionValue.assignedUserId || '',
    slackUserId: user.id || '',
    slackUserName: user.username || user.name || '',
    actionId: action.action_id || '',
    responseUrl: payload.response_url || '',
    triggerId: payload.trigger_id || ''
  }
}];

const parsed = $('Verify Signature & Parse').first().json;
const espoResult = $input.first().json;

const success = !!espoResult.id;
const statusEmoji = success ? '\u2705' : '\u26a0\ufe0f';
const statusLabel = success
  ? 'Acknowledged & In Progress'
  : 'Acknowledged (CRM update pending)';
const ts = Math.floor(Date.now() / 1000);

const blocks = [
  {
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `${statusEmoji} *${statusLabel}*\n_Acknowledged by <@${parsed.slackUserId}> <!date^${ts}^{date_short_pretty} at {time}|just now>_`
    }
  },
  {
    type: 'actions',
    elements: [
      {
        type: 'button',
        text: { type: 'plain_text', text: '\ud83d\udd17 Open in CRM', emoji: true },
        url: `https://rrespocrm-rsg-u69864.vm.elestio.app/#Task/view/${parsed.taskId}`
      }
    ]
  }
];

return [{
  json: {
    response_url: parsed.responseUrl,
    text: `${statusEmoji} ${statusLabel}`,
    blocks
  }
}];
